cpp_content = '\n// ═══════════════════════════════════════════════════════════════\n// 5. AppIconBase 体系实现\n// ═══════════════════════════════════════════════════════════════\nAppIconBase::AppIconBase(sf::Vector2f p, const std::string& lbl, const std::string& texPath, const sf::Font& font)\n    : UIComponent(p, ICON_W, ICON_CELL_H), label(lbl) {\n    sf::Image img;\n    if (img.loadFromFile(texPath)) {\n        img.createMaskFromColor(sf::Color::Black); // XP图标去黑底\n        iconTex.loadFromImage(img);\n        iconTex.setSmooth(true);\n        iconSpr.setTexture(iconTex);\n        iconSpr.setScale(ICON_W / iconTex.getSize().x, ICON_H / iconTex.getSize().y);\n    }\n    \n    labelText.setFont(font);\n    labelText.setCharacterSize(12);\n    labelText.setString(U8(label));\n    labelText.setFillColor(C::TextWhite);\n    \n    // 简单分行（对于长图标名）\n    sf::FloatRect tr = labelText.getLocalBounds();\n    if (tr.width > ICON_W * 1.5f) {\n        std::string wrap = U8(label).toAnsiString(); // Not perfect but ok for our labels\n        // Very basic wrap... for simplicity we just let it overflow a bit or center it\n    }\n}\n\nvoid AppIconBase::render(sf::RenderWindow& win) {\n    iconSpr.setPosition(position.x + (width - ICON_W)/2, position.y + 4.f);\n    \n    if (selected || highlight) {\n        sf::RectangleShape filter({ICON_W, ICON_H});\n        filter.setPosition(iconSpr.getPosition());\n        filter.setFillColor(highlight ? sf::Color(255, 255, 0, 100) : C::SelectIcon);\n        win.draw(filter);\n    }\n    win.draw(iconSpr);\n    \n    sf::FloatRect tr = labelText.getLocalBounds();\n    float tx = position.x + width/2 - tr.width/2;\n    float ty = position.y + ICON_H + 8.f;\n    \n    if (selected) {\n        sf::RectangleShape tbg({tr.width + 6.f, tr.height + 6.f});\n        tbg.setPosition(tx - 3.f, ty - 3.f);\n        tbg.setFillColor(C::SelectBlue);\n        win.draw(tbg);\n    } else {\n        // text shadow\n        sf::Text ts = labelText;\n        ts.setFillColor(sf::Color(0,0,0,150));\n        ts.setPosition(tx + 1.f, ty + 1.f);\n        win.draw(ts);\n    }\n    \n    labelText.setPosition(tx, ty);\n    win.draw(labelText);\n}\n\nbool AppIconBase::isMouseHit(sf::Vector2f mp) {\n    return bounds().contains(mp);\n}\n\nvoid AppIconBase::buildContextMenu(std::vector<MenuItem>& out) {\n    out.push_back({"打开(O)", [this](){ onDoubleClick(); }, true, false, true});\n    out.push_back({"属性(R)", nullptr, false});\n}\n\n// ── 具体图标实现 ──────────────────────────────\nMyDocumentsIcon::MyDocumentsIcon(sf::Vector2f p, const std::string& texPath, const sf::Font& font)\n    : AppIconBase(p, "我的文档", texPath, font) {}\n\nvoid MyDocumentsIcon::onDoubleClick() {\n    if (g_Desktop) {\n        FileListWin* win = new FileListWin("我的文档", false, {100, 100}, 500, 400, g_Desktop->systemFont);\n        win->addFile(new TextFile("项目备忘录.txt", "2008年 SpaceX 内部淘汰机密\\n\\n星舰首飞记录：20230420\\n...\\n(密钥分为两段，后半段已被删除)"));\n        win->addFile(new TextFile("加密提示.doc", "加密档案室的入口... 好像在系统属性里？"));\n        g_Desktop->addWindow(win);\n        StoryManager::getInstance().markDocClueRead();\n    }\n}\n\nvoid MyDocumentsIcon::buildContextMenu(std::vector<MenuItem>& out) {\n    AppIconBase::buildContextMenu(out);\n    out.insert(out.begin() + 1, {"", nullptr, false, true}); // separator\n    out.insert(out.begin() + 2, {"提示:星舰首飞藏在网页，密码不止一组数字", nullptr, false});\n}\n\nIEBrowserIcon::IEBrowserIcon(sf::Vector2f p, const std::string& texPath, const sf::Font& font)\n    : AppIconBase(p, "Internet\\nExplorer", texPath, font) {}\nvoid IEBrowserIcon::onDoubleClick() {\n    if (g_Desktop) g_Desktop->addWindow(new BrowserWindow({150, 150}, 600, 450, g_Desktop->systemFont));\n}\n\nRecycleBinIcon::RecycleBinIcon(sf::Vector2f p, const std::string& texPath, const sf::Font& font)\n    : AppIconBase(p, "回收站", texPath, font) {}\nvoid RecycleBinIcon::onDoubleClick() {\n    if (g_Desktop) {\n        if (!StoryManager::getInstance().recycleBinUnlocked) {\n            g_Desktop->addWindow(new MsgBoxWin("拒绝访问", "该文件夹已被加密系统锁定，禁止访问。\\n请先通过【加密档案室】验证权限。", {200, 200}, 300, 150, g_Desktop->systemFont));\n            return;\n        }\n        FileListWin* win = new FileListWin("回收站", true, {200, 200}, 500, 400, g_Desktop->systemFont);\n        win->addFile(new DeletedFile("特斯拉编号记录.txt", "车辆出厂编号：2012"));\n        g_Desktop->addWindow(win);\n    }\n}\n\nSecretFolderIcon::SecretFolderIcon(sf::Vector2f p, const std::string& texPath, const sf::Font& font)\n    : AppIconBase(p, "加密档案室", texPath, font) {}\nvoid SecretFolderIcon::onDoubleClick() {\n    if (g_Desktop) {\n        if (!StoryManager::getInstance().archiveOpened) {\n            // 未解锁状态，点击无响应或者提示\n            return;\n        }\n        FileListWin* win = new FileListWin("加密档案室", false, {250, 250}, 400, 300, g_Desktop->systemFont);\n        win->addFile(new TextFile("密钥上半段.txt", "完整密钥 = 试飞日期 + 特斯拉 Model S 出厂编号\\n后半段密钥已被移入回收站永久删除。"));\n        g_Desktop->addWindow(win);\n        StoryManager::getInstance().unlockRecycleBin();\n        highlight = false; // 解锁后取消高亮\n    }\n}\n\nTeslaExeIcon::TeslaExeIcon(sf::Vector2f p, const std::string& texPath, const sf::Font& font)\n    : AppIconBase(p, "Starship.exe", texPath, font) {}\nvoid TeslaExeIcon::onDoubleClick() {\n    if (g_Desktop) {\n        StoryManager::getInstance().triggerNormalEnding();\n    }\n}\n\nMyComputerIcon::MyComputerIcon(sf::Vector2f p, const std::string& texPath, const sf::Font& font)\n    : AppIconBase(p, "我的电脑", texPath, font) {}\nvoid MyComputerIcon::onDoubleClick() {\n    if (g_Desktop) {\n        FileListWin* win = new FileListWin("我的电脑", false, {50, 50}, 500, 400, g_Desktop->systemFont);\n        win->folderPath = "我的电脑";\n        win->addFile(new TextFile("C盘", "本地磁盘", "locked"));\n        win->addFile(new TextFile("D盘", "本地磁盘", "locked"));\n        g_Desktop->addWindow(win);\n    }\n}\nvoid MyComputerIcon::buildContextMenu(std::vector<MenuItem>& out) {\n    AppIconBase::buildContextMenu(out);\n    out.back() = {"属性(R)", [this](){\n        if (g_Desktop) g_Desktop->addWindow(new SystemPropWin({100, 100}, 400, 450, g_Desktop->systemFont));\n    }, true};\n}\n\n// ═══════════════════════════════════════════════════════════════\n// 6. Desktop 实现\n// ═══════════════════════════════════════════════════════════════\nDesktop::Desktop() {\n    g_Desktop = this;\n}\nDesktop::~Desktop() {\n    for (auto i : icons) delete i;\n    for (auto w : openWindows) delete w;\n    g_Desktop = nullptr;\n}\n\nvoid Desktop::init(sf::RenderWindow& win) {\n    renderWin = &win;\n    if (!systemFont.loadFromFile("C:\\\\Windows\\\\Fonts\\\\simsun.ttc") &&\n        !systemFont.loadFromFile("C:\\\\Windows\\\\Fonts\\\\msyh.ttc")) {\n        std::cerr << "Failed to load font!" << std::endl;\n    }\n    shellMenu.setFont(systemFont);\n    \n    sf::Image wImg;\n    if (wImg.loadFromFile("assets/wallpaper.jpg")) {\n        wallTex.loadFromImage(wImg);\n        wallTex.setSmooth(true);\n        wallSpr.setTexture(wallTex);\n        float sx = WIN_W / wImg.getSize().x;\n        float sy = DESKTOP_H / wImg.getSize().y;\n        wallSpr.setScale(std::max(sx, sy), std::max(sx, sy));\n        hasWallpaper = true;\n    }\n    \n    sf::Image sImg;\n    if (sImg.loadFromFile("assets/start.jpg")) {\n        sImg.createMaskFromColor(sf::Color::Black);\n        startTex.loadFromImage(sImg);\n        startTex.setSmooth(true);\n        startSpr.setTexture(startTex);\n        startSpr.setPosition(0, WIN_H - TASKBAR_H);\n        startSpr.setScale(TASKBAR_H / startTex.getSize().y, TASKBAR_H / startTex.getSize().y);\n    }\n    \n    taskbarBg.setSize({WIN_W, TASKBAR_H});\n    taskbarBg.setPosition(0, WIN_H - TASKBAR_H);\n    taskbarBg.setFillColor(C::TaskbarBg);\n    \n    clockText.setFont(systemFont);\n    clockText.setCharacterSize(14);\n    clockText.setFillColor(C::TextWhite);\n    clockText.setPosition(WIN_W - 60.f, WIN_H - TASKBAR_H + 12.f);\n    \n    startLabel.setFont(systemFont);\n    startLabel.setCharacterSize(16);\n    startLabel.setStyle(sf::Text::Bold | sf::Text::Italic);\n    startLabel.setFillColor(C::TextWhite);\n    startLabel.setString(U8("开始"));\n    startLabel.setPosition(35.f, WIN_H - TASKBAR_H + 10.f);\n\n    // 添加图标\n    icons.push_back(new MyDocumentsIcon({20, 20}, "assets/folder.jpg", systemFont));\n    icons.push_back(new MyComputerIcon({20, 130}, "assets/recycle.jpg", systemFont)); // Placeholder icon\n    icons.push_back(new IEBrowserIcon({20, 240}, "assets/notepad.jpg", systemFont)); // Placeholder\n    \n    recycleIcon = new RecycleBinIcon({20, 350}, "assets/recycle.jpg", systemFont);\n    icons.push_back(recycleIcon);\n    \n    secretIcon = new SecretFolderIcon({120, 20}, "assets/folder.jpg", systemFont);\n    icons.push_back(secretIcon);\n    \n    rewardIcon = new TeslaExeIcon({120, 130}, "assets/start.jpg", systemFont); // Placeholder\n    rewardIcon->visible = false;\n    icons.push_back(rewardIcon);\n}\n\nvoid Desktop::addWindow(PuzzleWindowBase* win) {\n    openWindows.push_back(win);\n    setActiveWindow(win);\n}\n\nvoid Desktop::bringToFront(PuzzleWindowBase* win) {\n    auto it = std::find(openWindows.begin(), openWindows.end(), win);\n    if (it != openWindows.end()) {\n        openWindows.erase(it);\n        openWindows.push_back(win);\n    }\n}\n\nvoid Desktop::setActiveWindow(PuzzleWindowBase* win) {\n    for (auto w : openWindows) w->isActive = false;\n    if (win) {\n        win->isActive = true;\n        bringToFront(win);\n    }\n}\n\nPuzzleWindowBase* Desktop::topWindow() const {\n    for (auto it = openWindows.rbegin(); it != openWindows.rend(); ++it) {\n        if ((*it)->isOpen && !(*it)->isMinimized) return *it;\n    }\n    return nullptr;\n}\n\nPuzzleWindowBase* Desktop::findWindowByTitle(const std::string& title) const {\n    for (auto w : openWindows) {\n        if (w->title.find(title) != std::string::npos) return w;\n    }\n    return nullptr;\n}\n\nbool Desktop::activateExisting(const std::string& title) {\n    PuzzleWindowBase* w = findWindowByTitle(title);\n    if (w) {\n        w->restoreFromTaskbar();\n        return true;\n    }\n    return false;\n}\n\nvoid Desktop::syncStoryVisuals() {\n    if (StoryManager::getInstance().isRewardUnlocked && rewardIcon) {\n        rewardIcon->visible = true;\n    }\n}\n\nvoid Desktop::hideShellMenu() { shellMenu.hide(); }\n\nstd::vector<PuzzleWindowBase*> Desktop::visibleTaskWindows() const {\n    std::vector<PuzzleWindowBase*> res;\n    for (auto w : openWindows) if (w->isOpen) res.push_back(w);\n    return res;\n}\n\nsf::FloatRect Desktop::taskButtonRect(std::size_t index) const {\n    float startX = 100.f; // After Start button\n    float w = TASK_BTN_W;\n    return {startX + index * (w + 4.f), WIN_H - TASKBAR_H + 4.f, w, TASKBAR_H - 8.f};\n}\n\nvoid Desktop::handleTaskbarClick(sf::Vector2f mp) {\n    if (startSpr.getGlobalBounds().contains(mp)) {\n        // Start button logic\n        std::vector<MenuItem> items;\n        items.push_back({"所有程序(P)", nullptr, true});\n        items.push_back({"", nullptr, false, true});\n        items.push_back({"注销(L)", nullptr, true});\n        items.push_back({"关闭计算机(U)", [this](){ renderWin->close(); }, true});\n        shellMenu.show({0, WIN_H - TASKBAR_H - items.size()*22.f - 6.f}, items);\n        return;\n    }\n    \n    auto vws = visibleTaskWindows();\n    for (std::size_t i = 0; i < vws.size(); ++i) {\n        if (taskButtonRect(i).contains(mp)) {\n            if (vws[i]->isActive && !vws[i]->isMinimized) vws[i]->minimizeWindow();\n            else vws[i]->restoreFromTaskbar();\n            return;\n        }\n    }\n}\n\nvoid Desktop::processEvents() {\n    sf::Event event;\n    while (renderWin->pollEvent(event)) {\n        if (event.type == sf::Event::Closed) renderWin->close();\n        \n        sf::Vector2f mp;\n        if (event.type == sf::Event::MouseButtonPressed || event.type == sf::Event::MouseButtonReleased || event.type == sf::Event::MouseMoved) {\n            mp = sf::Vector2f(sf::Mouse::getPosition(*renderWin));\n        }\n        \n        if (event.type == sf::Event::MouseMoved) {\n            shellMenu.updateHover(mp);\n            for (auto w : openWindows) {\n                if (w->isDragging) w->dragUpdate(mp);\n                if (w->isResizing) {\n                    if (w->resizeDir == 1 || w->resizeDir == 3) w->width = std::max(200.f, mp.x - w->position.x);\n                    if (w->resizeDir == 2 || w->resizeDir == 3) w->height = std::max(150.f, mp.y - w->position.y);\n                }\n            }\n        }\n        \n        if (event.type == sf::Event::MouseButtonReleased && event.mouseButton.button == sf::Mouse::Left) {\n            for (auto w : openWindows) {\n                w->isDragging = false;\n                w->isResizing = false;\n            }\n        }\n        \n        if (event.type == sf::Event::MouseButtonPressed) {\n            mp = sf::Vector2f(event.mouseButton.x, event.mouseButton.y);\n            \n            if (shellMenu.open) {\n                if (shellMenu.tryClick(mp)) continue;\n                hideShellMenu();\n                // 允许点击穿透关闭菜单\n            }\n            \n            if (mp.y >= WIN_H - TASKBAR_H) {\n                if (event.mouseButton.button == sf::Mouse::Left) handleTaskbarClick(mp);\n                continue;\n            }\n            \n            // Check windows top-down\n            bool hitWindow = false;\n            for (auto it = openWindows.rbegin(); it != openWindows.rend(); ++it) {\n                PuzzleWindowBase* w = *it;\n                if (!w->isOpen || w->isMinimized) continue;\n                \n                // Modal check: if there\'s a modal window, block interaction with other windows\n                PuzzleWindowBase* topModal = nullptr;\n                for (auto w2 : openWindows) if (w2->isOpen && !w2->isMinimized && w2->isModal) topModal = w2;\n                if (topModal && topModal != w) continue;\n                \n                if (w->isMouseHit(mp)) {\n                    hitWindow = true;\n                    setActiveWindow(w);\n                    if (event.mouseButton.button == sf::Mouse::Left) {\n                        int capHit = w->hitCaptionButton(mp);\n                        if (capHit == 0) w->closeWindow();\n                        else if (capHit == 1) w->toggleMaximize();\n                        else if (capHit == 2) w->minimizeWindow();\n                        else if (w->containsTitleBarDrag(mp)) {\n                            w->isDragging = true;\n                            w->dragOffset = mp - w->position;\n                        } else if (!w->isMaximized && mp.x > w->position.x + w->width - 8.f && mp.y > w->position.y + w->height - 8.f) {\n                            w->isResizing = true; w->resizeDir = 3;\n                        } else if (!w->isMaximized && mp.x > w->position.x + w->width - 8.f) {\n                            w->isResizing = true; w->resizeDir = 1;\n                        } else if (!w->isMaximized && mp.y > w->position.y + w->height - 8.f) {\n                            w->isResizing = true; w->resizeDir = 2;\n                        }\n                    } else if (event.mouseButton.button == sf::Mouse::Right) {\n                        if (w->clientRect().contains(mp)) {\n                            std::vector<MenuItem> items;\n                            w->buildClientContextMenu(items, mp);\n                            if (!items.empty()) shellMenu.show(mp, items);\n                        }\n                    }\n                    w->handleInput(event);\n                    break;\n                }\n            }\n            \n            if (!hitWindow) {\n                PuzzleWindowBase* topModal = nullptr;\n                for (auto w2 : openWindows) if (w2->isOpen && !w2->isMinimized && w2->isModal) topModal = w2;\n                \n                if (!topModal) {\n                    // Clicked on desktop background / icons\n                    for (auto w : openWindows) w->isActive = false;\n                    bool hitIcon = false;\n                    for (auto icon : icons) {\n                        if (!icon->visible) continue;\n                        if (icon->isMouseHit(mp)) {\n                            hitIcon = true;\n                            if (event.mouseButton.button == sf::Mouse::Left) {\n                                for (auto i2 : icons) i2->selected = false;\n                                icon->selected = true;\n                                if (lastClickedIcon == icon && clickClock.getElapsedTime().asMilliseconds() < DOUBLE_CLICK_MS) {\n                                    icon->onDoubleClick();\n                                }\n                                lastClickedIcon = icon;\n                                clickClock.restart();\n                            } else if (event.mouseButton.button == sf::Mouse::Right) {\n                                for (auto i2 : icons) i2->selected = false;\n                                icon->selected = true;\n                                std::vector<MenuItem> items;\n                                icon->buildContextMenu(items);\n                                if (!items.empty()) shellMenu.show(mp, items);\n                            }\n                            break;\n                        }\n                    }\n                    if (!hitIcon) {\n                        for (auto i2 : icons) i2->selected = false;\n                        if (event.mouseButton.button == sf::Mouse::Right) {\n                            std::vector<MenuItem> items;\n                            items.push_back({"排列图标(I)", nullptr, false});\n                            items.push_back({"刷新(E)", nullptr, true});\n                            items.push_back({"", nullptr, false, true});\n                            items.push_back({"属性(R)", nullptr, true});\n                            shellMenu.show(mp, items);\n                        }\n                    }\n                }\n            }\n        }\n        \n        // Pass keyboard input to active window\n        PuzzleWindowBase* active = topWindow();\n        if (active && (event.type == sf::Event::TextEntered || event.type == sf::Event::KeyPressed)) {\n            active->handleInput(event);\n        }\n    }\n}\n\nvoid Desktop::updateTaskbar() {\n    time_t now = time(nullptr);\n    struct tm* t = localtime(&now);\n    char buf[64];\n    strftime(buf, sizeof(buf), "%H:%M", t);\n    clockText.setString(buf);\n}\n\nvoid Desktop::renderTaskbar() {\n    renderWin->draw(taskbarBg);\n    \n    // Draw top light line\n    sf::RectangleShape tline({WIN_W, 1.f});\n    tline.setPosition(0, WIN_H - TASKBAR_H);\n    tline.setFillColor(sf::Color(255, 255, 255, 100));\n    renderWin->draw(tline);\n    \n    renderWin->draw(startSpr);\n    renderWin->draw(startLabel);\n    \n    auto vws = visibleTaskWindows();\n    for (std::size_t i = 0; i < vws.size(); ++i) {\n        sf::FloatRect br = taskButtonRect(i);\n        sf::RectangleShape btn(br.size);\n        btn.setPosition(br.position);\n        btn.setFillColor(vws[i]->isActive && !vws[i]->isMinimized ? C::TaskbarBtnAct : C::TaskbarBtn);\n        renderWin->draw(btn);\n        \n        // simple bevel\n        sf::RectangleShape bline({br.width, 1.f});\n        bline.setPosition(br.position); bline.setFillColor(sf::Color(255,255,255,50)); renderWin->draw(bline);\n        bline.setPosition(br.position.x, br.position.y+br.height-1.f); bline.setFillColor(sf::Color(0,0,0,100)); renderWin->draw(bline);\n        \n        sf::Text t = vws[i]->titleText;\n        t.setPosition(br.position.x + 10.f, br.position.y + 4.f);\n        \n        // clip text\n        std::string s = t.getString().toAnsiString();\n        if (s.length() > 15) { s = s.substr(0, 12) + "..."; t.setString(U8(s)); }\n        renderWin->draw(t);\n    }\n    \n    renderWin->draw(clockText);\n}\n\nvoid Desktop::renderAll() {\n    renderWin->clear(C::DesktopBg);\n    if (hasWallpaper) renderWin->draw(wallSpr);\n    \n    for (auto icon : icons) {\n        if (icon->visible) icon->render(*renderWin);\n    }\n    \n    for (auto w : openWindows) {\n        w->render(*renderWin);\n    }\n    \n    renderTaskbar();\n    shellMenu.render(*renderWin);\n    \n    renderWin->display();\n}\n\nvoid Desktop::run() {\n    while (renderWin->isOpen()) {\n        processEvents();\n        \n        // Remove closed windows\n        auto it = std::remove_if(openWindows.begin(), openWindows.end(), [](PuzzleWindowBase* w){ return !w->isOpen; });\n        for (auto i = it; i != openWindows.end(); ++i) delete *i;\n        openWindows.erase(it, openWindows.end());\n        \n        updateTaskbar();\n        renderAll();\n    }\n}\n'
